class DOMManager {
  constructor() {
    this.elements = [];
    this.handlers = new Map();
  }

  createElement(tag, parent) {
    const element = document.createElement(tag);
    parent.appendChild(element);

    // Track the element
    this.elements.push(element);

    // Add click handler for interactivity
    const handler = () => {
      console.log('Element clicked:', element.tagName);
    };

    element.addEventListener('click', handler);
    this.handlers.set(element, handler);

    return element;
  }

  removeElement(element) {
    // CRITICAL: Remove event listener FIRST
    const handler = this.handlers.get(element);
    if (handler) {
      element.removeEventListener('click', handler);
      this.handlers.delete(element);
    }

    // Remove from tracking array
    const index = this.elements.indexOf(element);
    if (index !== -1) {
      this.elements.splice(index, 1);
    }

    // Remove from DOM last
    if (element.parentNode) {
      element.parentNode.removeChild(element);
    }
  }
}

module.exports = DOMManager;
EOF

