const DOMManager = require('./src/dom-manager');

global.document = {
  createElement: (tag) => ({
    tagName: tag.toUpperCase(),
    parentNode: null,
    addEventListener: () => {},
    removeEventListener: () => {}
  })
};

const manager = new DOMManager();
const parent = {appendChild: () => {}, removeChild: () => {}};

// Create 100 elements
const elements = [];
for (let i = 0; i < 100; i++) {
  elements.push(manager.createElement('div', parent));
}

console.log('Created 100 elements');
console.log('Elements tracked:', manager.elements.length);
console.log('Handlers tracked:', manager.handlers.size);

// Remove all
for (const elem of elements) {
  manager.removeElement(elem);
}

console.log('\nAfter removing all:');
console.log('Elements tracked:', manager.elements.length);
console.log('Handlers tracked:', manager.handlers.size);
console.log('Complete cleanup - no leaks');
